local SumRecharges = {}

SumRechargeConfig = {}

local function initSumRecharges(config)
    for _, item in pairs(config) do
        table.insert(SumRecharges, {
            Id = item.Id,
            Sex = tonumber(item.Sex),
            GCube = tonumber(item.Gcube),
            DailyRemind = tonumber(item.DailyRemind) == 1,
            NextId = item.NextId,
            Rewards = {}
        })
    end
end

local function getSumRecharge(id)
    for _, config in pairs(SumRecharges) do
        if config.Id == id then
            return config
        end
    end
end

local function initSumRechargeRewards(rewards)
    for _, reward in pairs(rewards) do
        local config = getSumRecharge(reward.SumRechargeId)
        if config then
            table.insert(config.Rewards, {
                Type = reward.Type,
                RewardId = reward.RewardId,
                Count = reward.Count,
                Meta = tonumber(reward.Meta) or 0
            })
        end
    end
end

function SumRechargeConfig:init()
    local path = FileUtil:getMapPath() .. "common/SumRecharge.csv"
    local file = io.open(path, "r")
    if not file then
        return
    end
    io.close(file)
    initSumRecharges(CsvUtil.loadCsvFile(path, 2))
    path = FileUtil:getMapPath() .. "common/SumRechargeReward.csv"
    file = io.open(path, "r")
    if not file then
        return
    end
    io.close(file)
    initSumRechargeRewards(CsvUtil.loadCsvFile(path, 2))
    SumRechargeHelper:init()
end

function SumRechargeConfig:getSumRecharge(id)
    return getSumRecharge(id)
end

function SumRechargeConfig:getMinGCubeConfig(sex)
    local result
    for _, config in pairs(SumRecharges) do
        if config.Sex == sex or config.Sex == 0 then
            if result == nil then
                result = config
            end
            if result.GCube > config.GCube then
                result = config
            end
        end
    end
    return result
end